/**
 * Declarative map of every editable BrandConfig path → how the inspector
 * renders it. Co-located with the schema so drift is caught: the content
 * surface is generated by walking DEFAULT_CONTENT (the full ContentMap), and
 * registry.test.ts walks it the same way — a new content field fails the
 * coverage test until it appears here. Overrides/palette/assets are curated.
 */
import type { ContentMap } from '../config/schema'
import { DEFAULT_CONTENT, PALETTES } from '../config/defaults'

export type FieldKind =
  | 'mode'
  | 'color'
  | 'text'
  | 'textarea'
  | 'select'
  | 'number'
  | 'range'
  | 'list'
  | 'asset'
  | 'toneMap'

export interface FieldDef {
  path: string
  label: string
  kind: FieldKind
  group: string
  options?: string[]
  min?: number
  max?: number
  step?: number
}

export interface GroupDef {
  id: string
  label: string
  scope: 'page' | 'global' | 'assets'
  route?: string
}

export const GROUPS: readonly GroupDef[] = [
  { id: 'theme', label: 'Theme', scope: 'global' },
  { id: 'brand', label: 'Brand & Wordmark', scope: 'global' },
  { id: 'palette', label: 'Palette', scope: 'global' },
  { id: 'shape', label: 'Shape & Type', scope: 'global' },
  { id: 'nav', label: 'Navigation', scope: 'global' },
  { id: 'footer', label: 'Footer', scope: 'global' },
  { id: 'onboarding', label: 'Onboarding', scope: 'page', route: '/onboarding' },
  { id: 'missions', label: 'Missions', scope: 'page', route: '/missions' },
  { id: 'leaderboard', label: 'Leaderboard', scope: 'page', route: '/leaderboard' },
  { id: 'profile', label: 'Profile', scope: 'page', route: '/profile' },
  { id: 'assets', label: 'Assets', scope: 'assets' },
]

/** "titleBrand" → "Title Brand", "bg2" → "Bg2". */
function humanize(seg: string): string {
  return seg.replace(/([a-z0-9])([A-Z])/g, '$1 $2').replace(/^./, (c) => c.toUpperCase())
}

const CONTENT_GROUP: Record<keyof ContentMap, string> = {
  brand: 'brand',
  nav: 'nav',
  footer: 'footer',
  onboarding: 'onboarding',
  leaderboard: 'leaderboard',
  profile: 'profile',
  missions: 'missions',
}

function leafEntries(obj: unknown, prefix: string): { path: string; isArray: boolean }[] {
  if (obj === null || typeof obj !== 'object' || Array.isArray(obj)) {
    return [{ path: prefix, isArray: Array.isArray(obj) }]
  }
  return Object.entries(obj as Record<string, unknown>).flatMap(([k, v]) =>
    leafEntries(v, prefix ? `${prefix}.${k}` : k)
  )
}

function contentFields(): FieldDef[] {
  return leafEntries(DEFAULT_CONTENT, 'content').map(({ path, isArray }) => {
    const parts = path.split('.')
    const ns = parts[1] as keyof ContentMap
    const leaf = parts[parts.length - 1]
    const kind: FieldKind = isArray ? 'list' : leaf === 'body' ? 'textarea' : 'text'
    return { path, label: humanize(leaf), kind, group: CONTENT_GROUP[ns] }
  })
}

const C = (slots: string[]) => slots.map((s) => ({ slot: s, kind: 'color' as FieldKind }))

