function recipeFields(): FieldDef[] {
  return RECIPES.flatMap((r) =>
    r.fields.map((f) => ({
      path: `overrides.${r.recipe}.${f.slot}`,
      label: f.slot.split('.').map(humanize).join(' '),
      kind: f.kind,
      group: r.group,
      options: f.options,
      min: f.min,
      max: f.max,
      step: f.step,
    }))
  )
}

function buildFields(): FieldDef[] {
  const out: FieldDef[] = []
  out.push({ path: 'mode', label: 'Mode', kind: 'mode', group: 'theme' })
  out.push({ path: 'brand.primary', label: 'Primary', kind: 'color', group: 'brand' })
  out.push({ path: 'brand.secondary', label: 'Secondary', kind: 'color', group: 'brand' })
  out.push(...contentFields())
  for (const key of Object.keys(PALETTES.dark)) {
    out.push({
      path: `overrides.palette.${key}`,
      label: humanize(key),
      kind: 'color',
      group: 'palette',
    })
  }
  for (const r of ['card', 'button', 'tag', 'modal']) {
    out.push({
      path: `overrides.radius.${r}`,
      label: `Radius ${humanize(r)}`,
      kind: 'text',
      group: 'shape',
    })
  }
  for (const f of ['display', 'ui', 'mono']) {
    out.push({
      path: `overrides.fonts.${f}`,
      label: `Font ${humanize(f)}`,
      kind: 'text',
      group: 'shape',
    })
  }
  out.push(...recipeFields())
  out.push({
    path: 'assets.onboardingHero',
    label: 'Onboarding hero',
    kind: 'asset',
    group: 'assets',
  })
  out.push({ path: 'assets.missionsHero', label: 'Missions hero', kind: 'asset', group: 'assets' })
  return out
}

export const FIELDS: readonly FieldDef[] = buildFields()

export function fieldsForGroup(groupId: string): FieldDef[] {
  return FIELDS.filter((f) => f.group === groupId)
}
